module alu(
    input [31:0] a, b,
    input [5:0] aluc,
    output reg [31:0] r,
    output reg zero,
    output reg carry,
    output reg negative,
    output reg overflow,
    output reg flag
);

    localparam ADD = 6'b100000;
    localparam ADDU = 6'b100001;
    localparam SUB = 6'b100010;
    localparam SUBU = 6'b100011;
    localparam AND = 6'b100100;
    localparam OR = 6'b100101;
    localparam XOR = 6'b100110;
    localparam NOR = 6'b100111;
    localparam SLT = 6'b101010;
    localparam SLTU = 6'b101011;
    localparam SLL = 6'b000000;
    localparam SRL = 6'b000010;
    localparam SRA = 6'b000011;
    localparam SLLV = 6'b000100;
    localparam SRLV = 6'b000110;
    localparam SRAV = 6'b000111;
    localparam LUI = 6'b001111;

    wire [31:0] a_signed, b_signed;
    reg [32:0] res;

    assign a_signed = $signed(a);
    assign b_signed = $signed(b);

    always @(*) begin
        case(aluc)
            ADD: res <= a + b;
            ADDU: res <= a + b;
            SUB: res <= a - b;
            SUBU: res <= a - b;
            AND: res <= a & b;
            OR: res <= a | b;
            XOR: res <= a ^ b;
            NOR: res <= ~(a | b);
            SLT: res <= {1'b0, (a_signed < b_signed)};
            SLTU: res <= {1'b0, (a < b)};
            SLL: res <= {a, 32'b0} << b[4:0];
            SRL: res <= {32'b0, a} >> b[4:0];
            SRA: res <= {{(32-b[4:0]){a[31]}}, a} >> b[4:0];
            SLLV: res <= {a, 32'b0} << a[4:0];
            SRLV: res <= {32'b0, a} >> b[4:0];
            SRAV: res <= {{(32-a[4:0]){a[31]}}, a} >> a[4:0];
            LUI: res <= {b[15:0], 16'b0};
            default: res <= 33'hzzzzzzzzzz;
    endcase

    end // Auto-repaired
    always @(*) begin
        r <= res[31:0];
        zero <= (res == 32'h00000000);
        carry <= res[32];
        negative <= res[31];
        overflow <= ((a[31] & ~b[31]) | (~a[31] & b[31])) & ((~a[31] & ~b[31] & res[31]) | (a[31] & b[31] & ~res[31]));
        flag <= (aluc == SLT || aluc == SLTU) ? 1 : 0;
    end
endmodule
